import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Container, Row, Col, Button, Spinner, Alert, Card } from 'react-bootstrap';
import api from '../services/api';
import '../styles/card.css';

function EventDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchEventDetail = async () => {
      try {
        const response = await api.get(`/events/${id}`);
        setEvent(response.data);
      } catch (err) {
        console.error('Lỗi:', err);
      } finally {
        setLoading(false);
      }
    };
    fetchEventDetail();
  }, [id]);

  if (loading) return <div className="text-center mt-5"><Spinner animation="border" /></div>;
  if (!event) return <Container className="mt-5"><h3>Không tìm thấy sự kiện</h3></Container>;

  const eventDate = new Date(event.event_date);

  return (
    <Container fluid className="py-5 px-lg-5">
      <Row className="justify-content-center">
        <Col xs={12}>
          <Card className="ticket-detail-card border-0 shadow-lg overflow-hidden">
            <Row className="g-0">
              {/* CỘT THÔNG TIN (40%) */}
              <Col md={5} className="bg-white d-flex align-items-center">
                <div className="ticket-body w-100 p-5">
                  <h1 className="ticket-event-title mb-2">{event.title}</h1>
                  <p className="ticket-artist-name text-muted mb-4">by {event.artist_name || 'Organizer'}</p>

                  <div className="ticket-info-list">
                    <div className="info-item mb-3">
                      <div className="ticket-label">Ngày diễn ra</div>
                      <div className="ticket-value">
                        <i className="fa-regular fa-calendar-check me-2 text-primary"></i>
                        {eventDate.toLocaleDateString('vi-VN', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
                      </div>
                    </div>

                    <div className="info-item mb-3">
                      <div className="ticket-label">Thời gian</div>
                      <div className="ticket-value">
                        <i className="fa-regular fa-clock me-2 text-primary"></i>
                        {eventDate.toLocaleTimeString('vi-VN', { hour: '2-digit', minute: '2-digit' })}
                      </div>
                    </div>

                    <div className="info-item mb-3">
                      <div className="ticket-label">Địa điểm</div>
                      <div className="ticket-value location-text">
                        <i className="fa-solid fa-location-dot me-2 text-danger"></i>
                        {event.location}
                      </div>
                    </div>

                    <div className="info-item mb-4">
                      <div className="ticket-label">Giá vé từ</div>
                      <div className="ticket-value price-text">
                        <i className="fa-solid fa-tags me-2 text-success"></i>
                        {event.price ? `${event.price.toLocaleString('vi-VN')} VND` : 'Liên hệ'}
                      </div>
                    </div>
                  </div>

                  <Button variant="dark" className="btn-buy-ticket-large w-100 py-3 fw-bold">
                    MUA VÉ NGAY
                  </Button>
                </div>
              </Col>

              {/* CỘT HÌNH ẢNH (60%) */}
              <Col md={7}>
                <div className="ticket-image-wrapper h-100">
                  {/* <img 
                    src={event.banner_image ? `/images/${event.banner_image}` : 'https://via.placeholder.com/800x600'} 
                    alt={event.title} 
                    className="img-main-ticket"
                  /> */}
                  <img 
                    src={require(`../assets/images/${event.banner_image}`)} 
                    alt={event.title} 
                    />
                </div>
              </Col>
            </Row>
          </Card>

          {/* MÔ TẢ CHI TIẾT */}
          <div className="mt-5">
            <h4 className="fw-bold mb-4">Mô tả sự kiện</h4>
            <div className="event-desc-content p-4 bg-light rounded-4">
              {event.description}
            </div>
          </div>
        </Col>
      </Row>
    </Container>
  );
}

export default EventDetailPage;
